#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, P;
        scanf("%d %d", &N, &P);
        int cakewalk = 0, hard = 0;
        for (int i = 0; i < N; i++) {
            int x;
            scanf("%d", &x);
            if (x >= P / 2) cakewalk++;
            if (x <= P / 10) hard++;
        }
        if (cakewalk == 1 && hard == 2) printf("yes\n");
        else printf("no\n");
    }
    return 0;
}

