const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, P] = readline().split(' ').map(Number);
    let cakewalk = 0, hard = 0;
    const problems = readline().split(' ').map(Number);
    for (let j = 0; j < N; j++) {
        const x = problems[j];
        if (x >= P / 2) cakewalk++;
        if (x <= P / 10) hard++;
    }
    if (cakewalk === 1 && hard === 2) console.log('yes');
    else console.log('no');
}
